// Unit 7, ¿Dónde Está?
// Directions & Transport

export default {n:7,lang:"es",srcLang:"en",track:"v2",title:"¿Dónde Está?",sub:"Directions & Transport",icon:"🗺️",level:"A1.3",color:"#7B5EE8",lessons:[
  {id:"esp7l1",title:"Lugares de la Ciudad",icon:"🏙️",xp:15,board:true,steps:[
        {type:"intro",title:"Lugares de la Ciudad",desc:"Learn the names of important places you will find in any Spanish-speaking city.",goals:["Name 8 common city places","Use estar to locate places","Ask where places are"]},
        {type:"teach",trg:"el banco",src:"the bank",pos:"noun",gender:"m",phonetic:"el BAN-koh",note:"Where you go for money. Not a bench (that is el banquete).",example:"A: ¿Dónde está el banco?\nB: El banco está en la calle Mayor.\nA: Gracias, señor.",exampleSrc:"A: Where is the bank?\nB: The bank is on Main Street.\nA: Thank you, sir.",funFact:"Bank (financial + bench). Same word, two meanings: financial bank or park bench. Etymologically one: medieval Italian bankers worked at benches (banche) in piazzas."},
        {type:"teach",trg:"la farmacia",src:"the pharmacy",pos:"noun",gender:"f",phonetic:"la far-MA-see-ah",note:"Look for the green cross sign in Spanish cities.",example:"A: Necesito una farmacia.\nB: Hay una farmacia cerca de aquí.\nA: ¿Dónde exactamente?",exampleSrc:"A: I need a pharmacy.\nB: There is a pharmacy near here.\nA: Where exactly?",funFact:"In Spain, pharmacists can give medical advice and many medications are available without a prescription. The neon green cross is a universal symbol for farmacia."},
        {type:"teach",trg:"el hospital",src:"the hospital",pos:"noun",gender:"m",phonetic:"el os-pee-TAL",note:"Stress falls on the last syllable: hospiTAL.",example:"A: ¿El hospital está lejos?\nB: No, está muy cerca.\nA: ¡Qué bien!",exampleSrc:"A: Is the hospital far?\nB: No, it is very close.\nA: That's great!",funFact:"From Latin hospitium (lodging, guesthouse). The original hospitals served travelers and the sick. English 'hospital' and 'hostel' share this root."},
        {type:"teach",trg:"la estación",src:"the station",pos:"noun",gender:"f",phonetic:"la es-tah-see-ON",note:"Can be la estación de tren (train) or de autobús (bus).",example:"A: ¿Dónde está la estación?\nB: La estación está al final de esta calle.\nA: Muchas gracias.",exampleSrc:"A: Where is the station?\nB: The station is at the end of this street.\nA: Thank you very much.",funFact:"Cognate with English 'station'. Spanish and English share many Latin-derived words."},
        {type:"teach",trg:"el supermercado",src:"the supermarket",pos:"noun",gender:"m",phonetic:"el soo-per-mer-KA-doh",note:"A large grocery store. A smaller one is la tienda.",example:"A: ¿Hay un supermercado aquí?\nB: Sí, hay uno al lado del banco.\nA: Perfecto.",exampleSrc:"A: Is there a supermarket here?\nB: Yes, there is one next to the bank.\nA: Perfect.",funFact:"Super + mercado (market). Mercadona and Carrefour are two of Spain's biggest chains. Many Spaniards still shop daily at small local shops rather than weekly at supermarkets."},
        {type:"teach",trg:"la iglesia",src:"the church",pos:"noun",gender:"f",phonetic:"la ee-GLEH-see-ah",note:"Every Spanish town has one in the plaza central.",example:"A: ¿Ves la iglesia?\nB: Sí, es muy bonita.\nA: Es muy antigua.",exampleSrc:"A: Do you see the church?\nB: Yes, it is very beautiful.\nA: It is very old.",funFact:"Church. From Greek 'ekklesia' (assembly) via Latin. Same root as English 'ecclesiastical.' Every Spanish town has 'la iglesia' in the main plaza."},
        {type:"teach",trg:"el parque",src:"the park",pos:"noun",gender:"m",phonetic:"el PAR-keh",note:"A green space in the city. El Retiro is famous in Madrid.",example:"A: ¿Vamos al parque?\nB: Sí, el parque está cerca.\nA: ¡Vamos!",exampleSrc:"A: Shall we go to the park?\nB: Yes, the park is close.\nA: Let's go!",funFact:"Park. From French 'parc,' ultimately Germanic. Same root as English 'park' and 'parking.' Urban green space concept spread from French city planning."},
        {type:"teach",trg:"el museo",src:"the museum",pos:"noun",gender:"m",phonetic:"el moo-SEH-oh",note:"El Prado in Madrid is one of the world's great museums.",example:"A: ¿Te gusta el museo?\nB: Sí, me gusta mucho el museo de arte.\nA: A mí también.",exampleSrc:"A: Do you like the museum?\nB: Yes, I like the art museum a lot.\nA: Me too.",funFact:"From Greek mouseion (temple of the Muses). Madrid's Paseo del Prado has three world-class museums in walking distance: Prado, Thyssen, and Reina Sofía."},
        {type:"tip",title:"Estar for Location",text:"Use estar (not ser) to say where something IS located:\n\nEl banco está aquí. (The bank is here.)\nLa farmacia está lejos. (The pharmacy is far.)\n\nRemember: estar = location and condition.\nser = identity and characteristics."},
        {type:"mc",q:"¿Dónde compras comida?",opts:["En el supermercado","En el hospital","En la iglesia","En el museo"],ans:"En el supermercado",hint:"Think about which place sells food and groceries."},
        {type:"mc",q:"You need medicine. Where do you go?",opts:["El banco","La farmacia","El parque","La estación"],ans:"La farmacia",hint:"This place has a green cross sign outside."},
        {type:"fb",opts:["está","es","hay","son"],hint:"You are describing where something is located.",s:"El hospital {1} cerca de aquí.",a:"está"},
        {type:"fb",opts:["está","es","hay","son"],hint:"Asking about the location of a specific place.",s:"¿Dónde {1} la estación de tren?",a:"está"},
        {type:"match",pairs:[{trg:"el banco",src:"the bank"},{trg:"la farmacia",src:"the pharmacy"},{trg:"el hospital",src:"the hospital"},{trg:"la estación",src:"the station"},{trg:"el supermercado",src:"the supermarket"}]},
        {type:"mc",q:"La iglesia está en la plaza central. What is the iglesia?",opts:["The library","The school","The church","The theater"],ans:"The church",hint:"This building is often found in the main square of Spanish towns."},
        {type:"fb",opts:["parque","está","banco está","iglesia está"],hint:"You want to find a green space to relax outdoors.",s:"¿Hay un {1} cerca de aquí?",a:"parque"},
        {type:"mc",q:"Which place would you visit to see paintings and sculptures?",opts:["El supermercado","El banco","La estación","El museo"],ans:"El museo",hint:"This is where art and historical objects are displayed."},
        {type:"mc",q:"El parque está al lado del museo. What does 'al lado del' mean?",opts:["Next to","Far from","Behind","In front of"],ans:"Next to",hint:"You learned this preposition when describing your home."}
  ]},
  {id:"esp7l2",title:"¿Dónde Está...?",icon:"❓",xp:15,board:true,steps:[
        {type:"intro",title:"¿Dónde Está...?",desc:"Learn how to ask for directions politely in Spanish.",goals:["Ask where places are","Use polite expressions","Understand simple location answers"]},
        {type:"teach",trg:"¿Dónde está...?",src:"Where is...?",pos:"intj",gender:null,phonetic:"DON-deh es-TA",note:"The most common way to ask for a location.",example:"A: Perdone, ¿dónde está el banco?\nB: Está en la calle Sol.\nA: Gracias.",exampleSrc:"A: Excuse me, where is the bank?\nB: It is on Sol Street.\nA: Thank you.",funFact:"Uses estar, not ser, because location is a state, not identity. '¿Dónde es la fiesta?' is a rare exception; events use ser for the place they take place."},
        {type:"teach",trg:"¿Cómo llego a...?",src:"How do I get to...?",pos:"intj",gender:null,phonetic:"KO-moh YEH-goh ah",note:"Llegar means to arrive. Llego is the yo form.",example:"A: ¿Cómo llego al hospital?\nB: Sigue todo recto.\nA: ¿Está lejos?",exampleSrc:"A: How do I get to the hospital?\nB: Go straight ahead.\nA: Is it far?",funFact:"Literally 'how do I arrive at.' Present tense functions as future for travel plans. English 'how do I get to' uses similar present-for-future logic."},
        {type:"teach",trg:"perdone",src:"excuse me (formal)",pos:"intj",gender:null,phonetic:"per-DOH-neh",note:"Formal form of perdonar. Use with strangers.",example:"A: Perdone, ¿hay una farmacia por aquí?\nB: Sí, hay una en la esquina.\nA: Muchas gracias.",exampleSrc:"A: Excuse me, is there a pharmacy around here?\nB: Yes, there is one on the corner.\nA: Thank you very much.",funFact:"Formal command (usted) of 'perdonar.' Said when stopping a stranger on the street. Informal equivalent: 'perdona.' The -e/-a switch marks register."},
        {type:"teach",trg:"disculpe",src:"excuse me, pardon me (formal)",pos:"intj",gender:null,phonetic:"dis-KOOL-peh",note:"Slightly more formal than perdone. Both work with strangers.",example:"A: Disculpe, ¿dónde está el metro?\nB: El metro está detrás de la iglesia.\nA: Perfecto, gracias.",exampleSrc:"A: Excuse me, where is the metro?\nB: The metro is behind the church.\nA: Perfect, thank you.",funFact:"Formal command of 'disculpar.' Slightly less apologetic than 'perdone'; more 'excuse me.' Waiter-calling is almost always 'disculpe' in restaurants."},
        {type:"teach",trg:"por aquí",src:"around here",pos:"intj",gender:null,phonetic:"por ah-KEE",note:"Use when you want to find something nearby.",example:"A: ¿Hay un banco por aquí?\nB: Sí, hay uno muy cerca.\nA: ¿Dónde exactamente?",exampleSrc:"A: Is there a bank around here?\nB: Yes, there is one very close.\nA: Where exactly?",funFact:"'Por' implies through or around, not a point destination. 'Por aquí' = 'around here' or 'this way.' 'Aquí' alone is just 'here'; a precise spot."},
        {type:"teach",trg:"la calle",src:"the street",pos:"noun",gender:"f",phonetic:"la KA-yeh",note:"The main road through a city. La avenida is a wider road.",example:"A: ¿En qué calle está el museo?\nB: Está en la calle Alcalá.\nA: Gracias, disculpe.",exampleSrc:"A: On which street is the museum?\nB: It is on Alcalá Street.\nA: Thank you, excuse me.",funFact:"Street. From Latin 'callis' (path). Calles in Spanish cities tend to be named after dates ('Calle de Mayo'), people, or trades ('Calle de los Zapateros')."},
        {type:"tip",title:"Asking for Directions",text:"Two common patterns:\n\n1. ¿Dónde está + place?\n   ¿Dónde está el banco?\n\n2. ¿Cómo llego a + place?\n   ¿Cómo llego al museo?\n\nNote: a + el = al.\nStart with perdone or disculpe to be polite."},
        {type:"mc",q:"You want to find the station. What do you ask?",opts:["¿Dónde está la estación?","¿Cómo es la estación?","¿Cuándo está la estación?","¿Quién está la estación?"],ans:"¿Dónde está la estación?",hint:"You need the qu___ion word for location, not time or identity."},
        {type:"mc",q:"What does '¿Cómo llego al parque?' mean?",opts:["Where is the park?","How do I get to the park?","Do you like the park?","Is the park open?"],ans:"How do I get to the park?",hint:"Llegar means to arrive. Cómo asks about the manner or way."},
        {type:"fb",opts:["dónde","cómo","cuándo","quién"],hint:"You need the question word that asks about a place.",s:"Perdone, ¿{1} está la farmacia?",a:"dónde"},
        {type:"fb",opts:["llego","está","hay","es"],hint:"You need the yo form of the verb meaning to arrive.",s:"¿Cómo {1} al hospital?",a:"llego"},
        {type:"match",pairs:[
          {trg:"¿Dónde está?",src:"Where is it?"},
          {trg:"perdone",src:"excuse me"},
          {trg:"disculpe",src:"pardon me"},
          {trg:"por aquí",src:"around here"},
          {trg:"la calle",src:"the street"},
          {trg:"¿Cómo llego?",src:"How do I get there?"}
        ]},
        {type:"mc",q:"Perdone, ¿hay un supermercado por aquí? What does 'por aquí' mean?",opts:["Very far","Over there","Around here","Next door"],ans:"Around here",hint:"This phrase refers to the general nearby area."},
        {type:"fb",opts:["farmacia","cómo","dónde","está"],hint:"You need medicine. Which place sells it?",s:"Disculpe, ¿hay una {1} por aquí?",a:"farmacia"},
        {type:"mc",q:"Which expression is used to politely get a stranger's attention?",opts:["Gracias","Hola","Adiós","Perdone"],ans:"Perdone",hint:"This word comes from the verb perdonar."},
        {type:"fb",opts:["el","la","un","los"],hint:"Museo is a masculine noun. Which article fits?",s:"¿Dónde está {1} museo?",a:"el"},
        {type:"mc",q:"El banco está en la calle Mayor. Where is the bank?",opts:["On Mayor Street","In the park","Behind the church","Next to the station"],ans:"On Mayor Street",hint:"La calle means the ___. ___ is the name of the ___."}
  ]},
  {id:"esp7l3",title:"Gira a la Derecha",icon:"➡️",xp:15,board:true,steps:[
        {type:"intro",title:"Gira a la Derecha",desc:"Learn how to give and understand basic directions in Spanish.",goals:["Give simple directions","Understand left, right, straight","Use direction phrases with confidence"]},
        {type:"teach",trg:"todo recto",src:"straight ahead",pos:"intj",gender:null,phonetic:"TOH-doh REK-toh",note:"The most common direction. Recto means straight.",example:"A: ¿Cómo llego al banco?\nB: Sigue todo recto.\nA: ¿Y luego?",exampleSrc:"A: How do I get to the bank?\nB: Go straight ahead.\nA: And then?",funFact:"'Recto' means straight, not right. 'Derecho' is right (direction). Tourists often mix these. 'Siga todo recto' = keep going straight; 'a la derecha' = to the right."},
        {type:"teach",trg:"a la derecha",src:"to the right",pos:"verb",gender:null,phonetic:"ah la deh-REH-chah",note:"La derecha is the right side. Use with girar (to turn).",example:"A: ¿Dónde está la farmacia?\nB: Gira a la derecha.\nA: Gracias.",exampleSrc:"A: Where is the pharmacy?\nB: Turn to the right.\nA: Thank you.",funFact:"'To the right.' Direction preposition 'a' + la + derecha. Contrast: 'de la derecha' (from the right), 'por la derecha' (along the right)."},
        {type:"teach",trg:"a la izquierda",src:"to the left",pos:"verb",gender:null,phonetic:"ah la eez-kee-EHR-dah",note:"La izquierda is the left side. Careful with the spelling.",example:"A: ¿Cómo llego a la estación?\nB: Gira a la izquierda en la esquina.\nA: ¿En la primera esquina?",exampleSrc:"A: How do I get to the station?\nB: Turn left at the corner.\nA: At the first corner?",funFact:"'To the left.' Mirror of 'a la derecha.' Interestingly, 'izquierda' from Basque 'ezker'; one of Spanish's few Basque loanwords."},
        {type:"teach",trg:"en la esquina",src:"on the corner",pos:"intj",gender:null,phonetic:"en la es-KEE-nah",note:"La esquina is where two streets meet.",example:"A: ¿Dónde está el banco?\nB: Está en la esquina.\nA: ¿En esta esquina?",exampleSrc:"A: Where is the bank?\nB: It is on the corner.\nA: On this corner?",funFact:"'Esquina' is the outside corner of a street/building. 'Rincón' is the inside corner (of a room). Spanish distinguishes what English fuses into one word."},
        {type:"teach",trg:"al final de",src:"at the end of",pos:"intj",gender:null,phonetic:"al fee-NAL deh",note:"El final means the end. Al final de = at the end of.",example:"A: ¿Dónde está el parque?\nB: Está al final de esta calle.\nA: No está lejos entonces.",exampleSrc:"A: Where is the park?\nB: It is at the end of this street.\nA: It is not far then.",funFact:"Literally 'at the final of.' Covers English 'at the end of' for both physical (street) and temporal (year). 'Al principio de' is the matching opposite."},
        {type:"teach",trg:"la primera calle",src:"the first street",pos:"noun",gender:"f",phonetic:"la pree-MEH-rah KA-yeh",note:"Primera = first, segunda = second, tercera = third.",example:"A: ¿Cómo llego al museo?\nB: Toma la primera calle a la derecha.\nA: ¡Entendido!",exampleSrc:"A: How do I get to the museum?\nB: Take the first street on the right.\nA: Got it!",funFact:"'Primera' apocopes to 'primer' before masculine nouns (el primer libro) but stays 'primera' before feminine (la primera calle). Small but regular rule."},
        {type:"tip",title:"Giving Directions",text:"Common direction patterns:\n\nSigue todo recto. (Go straight.)\nGira a la derecha. (Turn right.)\nGira a la izquierda. (Turn left.)\nEstá en la esquina. (It is on the corner.)\nEstá al final de la calle. (It is at the end of the street.)\nToma la primera calle. (Take the first street.)"},
        {type:"mc",q:"Someone says: 'Gira a la izquierda.' What should you do?",opts:["Turn left","Turn right","Go straight","Go back"],ans:"Turn left",hint:"Izquierda is the opposite of derecha."},
        {type:"mc",q:"The museum is where two streets meet. Where is it?",opts:["Al final de la calle","En la esquina","Todo recto","A la derecha"],ans:"En la esquina",hint:"The point where two streets cross has a specific name."},
        {type:"fb",opts:["recto","derecha","izquierda","esquina"],hint:"This word means straight, describing the direction ahead of you.",s:"Sigue todo {1} y luego gira a la derecha.",a:"recto"},
        {type:"fb",opts:["final","lado","esquina","recto"],hint:"The hospital is at the very end, where the street stops.",s:"El hospital está al {1} de esta calle.",a:"final"},
        {type:"match",pairs:[
          {trg:"todo recto",src:"straight ahead"},
          {trg:"a la derecha",src:"to the right"},
          {trg:"a la izquierda",src:"to the left"},
          {trg:"en la esquina",src:"on the corner"},
          {trg:"al final de",src:"at the end of"}
        ]},
        {type:"mc",q:"¿Cómo llego al supermercado? 'Toma la primera calle a la derecha.' What does this mean?",opts:["Go straight to the supermarket","Take the first street on the left","Take the first street on the right","The supermarket is on the corner"],ans:"Take the first street on the right",hint:"Primera means ___, and derecha is one of the two sides."},
        {type:"fb",opts:["derecha","recto","final","calle"],hint:"You need to make a turn, not go straight. Pick the right side.",s:"Gira a la {1} en la esquina.",a:"derecha"},
        {type:"mc",q:"Which phrase means 'at the end of this street'?",opts:["A la derecha de esta calle","En la esquina de esta calle","Todo recto por esta calle","Al final de esta calle"],ans:"Al final de esta calle",hint:"You are looking for the phrase with the word for end."},
        {type:"fb",opts:["primera","segunda","derecha","recto"],hint:"You need the ordinal number for number one.",s:"Toma la {1} calle a la izquierda.",a:"primera"},
        {type:"mc",q:"Perdone, ¿cómo llego a la iglesia? 'Sigue todo recto y está a la izquierda.' Where is the church?",opts:["Straight ahead, then on the left","Straight ahead, then on the right","On the corner to the right","At the end of the first street"],ans:"Straight ahead, then on the left",hint:"Recto means ___, and izquierda is the opposite of derecha."}
  ]},
  {id:"esp7l4",title:"El Transporte",icon:"🚌",xp:15,board:true,steps:[
        {type:"intro",title:"El Transporte",desc:"Learn vocabulary for different types of transport used to get around the city and beyond.",goals:["Name 7 types of transport","Talk about how you travel","Use transport vocabulary in sentences"]},
        {type:"teach",trg:"el autobús",src:"the bus",pos:"noun",gender:"m",phonetic:"el ow-toh-BOOS",note:"Stress on the last syllable. Plural: los autobuses.",example:"A: ¿Tomas el autobús?\nB: Sí, tomo el autobús todos los días.\nA: ¿A qué hora llega?",exampleSrc:"A: Do you take the bus?\nB: Yes, I take the bus every day.\nA: What time does it arrive?",funFact:"Bus. Shortened from Latin 'omnibus' (for all). 'Auto-' was added, then dropped in English. Spanish kept the 'auto-' part: auto-bus = self-moving bus-for-all."},
        {type:"teach",trg:"el tren",src:"the train",pos:"noun",gender:"m",phonetic:"el tren",note:"Short and easy to remember. El AVE is Spain's high speed train.",example:"A: ¿Vamos en tren?\nB: Sí, el tren es rápido.\nA: ¿Dónde está la estación?",exampleSrc:"A: Shall we go by train?\nB: Yes, the train is fast.\nA: Where is the station?",funFact:"Train. From French 'train' (line of wagons). Late loanword (19th c. with railway expansion). Short, foreign-feeling in Spanish."},
        {type:"teach",trg:"el metro",src:"the metro, subway",pos:"noun",gender:"m",phonetic:"el MEH-troh",note:"Madrid, Barcelona, and México City have large metro systems.",example:"A: ¿Hay metro en esta ciudad?\nB: Sí, la estación de metro está cerca.\nA: Perfecto.",exampleSrc:"A: Is there a metro in this city?\nB: Yes, the metro station is nearby.\nA: Perfect.",funFact:"Short for metropolitano. Madrid's Metro, opened in 1919, is one of the oldest in the world. Mexico City's has the highest ridership in the Americas."},
        {type:"teach",trg:"el taxi",src:"the taxi",pos:"noun",gender:"m",phonetic:"el TAK-see",note:"Taxis are usually white in Spain, yellow or green in Latin America.",example:"A: Necesito un taxi.\nB: Hay una parada de taxi en la esquina.\nA: Gracias.",exampleSrc:"A: I need a taxi.\nB: There is a taxi stand on the corner.\nA: Thank you.",funFact:"From French taximètre (taxi-meter). The word is nearly identical in 30+ languages, making it one of the most universal loanwords in the world."},
        {type:"teach",trg:"el avión",src:"the airplane",pos:"noun",gender:"m",phonetic:"el ah-bee-ON",note:"El aeropuerto is the airport.",example:"A: ¿Viajas en avión?\nB: Sí, voy a Madrid en avión.\nA: ¡Qué emocionante!",exampleSrc:"A: Do you travel by plane?\nB: Yes, I go to Madrid by plane.\nA: How exciting!",funFact:"From Latin avis (bird). Coined in 1875 by French inventor Clément Ader. The accent on avión is required. Without it, the word would be stressed on the wrong syllable."},
        {type:"teach",trg:"el barco",src:"the boat, ship",pos:"noun",gender:"m",phonetic:"el BAR-koh",note:"Can mean a small boat or a large ship.",example:"A: ¿Te gusta viajar en barco?\nB: Sí, me gusta mucho.\nA: El mar es muy bonito.",exampleSrc:"A: Do you like traveling by boat?\nB: Yes, I like it a lot.\nA: The sea is very beautiful.",funFact:"Boat / ship. From Vulgar Latin 'barcus' (small vessel). Also root of English 'bark' (ship) and 'barge.' Old Mediterranean maritime vocabulary."},
        {type:"teach",trg:"la bicicleta",src:"the bicycle",pos:"noun",gender:"f",phonetic:"la bee-see-KLEH-tah",note:"Often shortened to la bici in spoken Spanish.",example:"A: ¿Tienes bicicleta?\nB: Sí, voy al parque en bicicleta.\nA: ¡Qué bien!",exampleSrc:"A: Do you have a bicycle?\nB: Yes, I go to the park by bicycle.\nA: How nice!",funFact:"From bi- (two) + ciclo (wheel). Cycling is hugely popular in Spain. La Vuelta a España is one of cycling's three Grand Tours, alongside the Tour de France and Giro d'Italia."},
        {type:"tip",title:"En + Transport",text:"To say how you travel, use en + transport:\n\nen autobús (by bus)\nen tren (by train)\nen metro (by metro)\nen taxi (by taxi)\nen avión (by plane)\nen barco (by boat)\nen bicicleta (by bicycle)\n\nException: a pie means on foot (not en pie)."},
        {type:"mc",q:"How do you say 'by train' in Spanish?",opts:["En tren","A tren","Con tren","Por tren"],ans:"En tren",hint:"The preposition for transport is a two-letter word meaning in."},
        {type:"mc",q:"You want to travel across the ocean. Which transport do you use?",opts:["El autobús","El barco","La bicicleta","El metro"],ans:"El barco",hint:"You need something that floats on water."},
        {type:"fb",opts:["autobús","avión","barco","pie"],hint:"This is the most common public transport for daily commuting.",s:"Voy al trabajo en {1} todos los días.",a:"autobús"},
        {type:"fb",opts:["metro","taxi","barco","avión"],hint:"This underground transport system runs beneath the city streets.",s:"La estación de {1} está debajo de la calle.",a:"metro"},
        {type:"match",pairs:[
          {trg:"el autobús",src:"the bus"},
          {trg:"el tren",src:"the train"},
          {trg:"el metro",src:"the metro"},
          {trg:"el avión",src:"the airplane"},
          {trg:"el barco",src:"the boat"},
          {trg:"la bicicleta",src:"the bicycle"}
        ]},
        {type:"mc",q:"Voy al parque en bicicleta. How does the speaker get to the park?",opts:["On foot","By bus","By bicycle","By taxi"],ans:"By bicycle",hint:"La bicicleta has two wheels and you pedal it."},
        {type:"mc",q:"Which is the exception to the 'en + transport' rule?",opts:["En tren","En coche","En taxi","A pie"],ans:"A pie",hint:"Walking uses a different preposition than vehicles."},
        {type:"fb",opts:["avión","pie","bicicleta","esquina"],hint:"Madrid is far away. You need the fastest transport.",s:"¿Viajas en {1} a Madrid?",a:"avión"},
        {type:"mc",q:"Necesito un taxi. Hay una parada de taxi en la esquina. What is a 'parada de taxi'?",opts:["A taxi stand","A taxi driver","A taxi ride","A taxi price"],ans:"A taxi stand",hint:"La parada is the place where you wait for transport to stop."}
  ]},
  {id:"esp7l5",title:"Ir + a",icon:"🚶",xp:15,board:true,steps:[
        {type:"intro",title:"Ir + a",desc:"Learn to use the verb ir (to go) with destinations and future actions.",goals:["Conjugate ir in the present","Use ir + a + place","Use ir + a + infinitive for near future"]},
        {type:"teach",trg:"voy a",src:"I go to, I am going to",pos:"intj",gender:null,phonetic:"boy ah",note:"Yo voy. Ir is very irregular. Voy a + place = going to a place.",example:"A: ¿Adónde vas?\nB: Voy a la estación.\nA: ¿En autobús?",exampleSrc:"A: Where are you going?\nB: I am going to the station.\nA: By bus?",funFact:"'Ir' + a + infinitive = Spanish future. 'Voy a comer' = I'm going to eat. No separate future tense needed for most near-future actions."},
        {type:"teach",trg:"vas a",src:"you go to (informal)",pos:"intj",gender:null,phonetic:"bas ah",note:"Tú vas. Used with friends and family.",example:"A: ¿Vas al supermercado?\nB: Sí, voy a comprar fruta.\nA: ¿Me compras manzanas?",exampleSrc:"A: Are you going to the supermarket?\nB: Yes, I am going to buy fruit.\nA: Can you buy me apples?",funFact:"Same ir+a+infinitive future. The yo/tú forms are irregular: 'voy/vas' diverge from the expected '*iro/iras.' Ir is the most irregular verb in Spanish."},
        {type:"teach",trg:"va a",src:"he/she/you(formal) goes to",pos:"intj",gender:null,phonetic:"ba ah",note:"Él/ella/usted va. One form for all three.",example:"A: ¿Adónde va María?\nB: Va al hospital.\nA: ¿Está enferma?",exampleSrc:"A: Where is María going?\nB: She is going to the hospital.\nA: Is she sick?",funFact:"Shared form for él, ella, and usted. Context or subject pronoun disambiguates. 'Él va a comer' vs 'usted va a comer'; same verb, different listener."},
        {type:"teach",trg:"vamos a",src:"we go to, we are going to",pos:"intj",gender:null,phonetic:"BA-mohs ah",note:"Nosotros vamos. Also used as Let's go!",example:"A: ¿Vamos al parque?\nB: ¡Sí, vamos!\nA: ¡Vamos en bicicleta!",exampleSrc:"A: Shall we go to the park?\nB: Yes, let's go!\nA: Let's go by bicycle!",funFact:"Also means 'let's' + infinitive! '¡Vamos a bailar!' can be 'we are going to dance' OR 'let's dance.' Tone and context separate the two senses."},
        {type:"teach",trg:"van a",src:"they/you(plural) go to",pos:"intj",gender:null,phonetic:"ban ah",note:"3rd person plural of ir (to go). 'Van a + infinitive' = they/you-all are going to. Immediate future tense.",example:"A: ¿Adónde van tus padres?\nB: Van al museo.\nA: ¡Qué interesante!",exampleSrc:"A: Where are your parents going?\nB: They are going to the museum.\nA: How interesting!",funFact:"Forms the plural near-future: 'ellos van a venir.' Also the third-person plural of ir in the present: 'ellos van al parque' (they go to the park)."},
        {type:"tip",title:"Ir + a: Two Uses",text:"Ir + a has two important uses:\n\n1. Going to a PLACE:\n   Voy al banco. (I go to the bank.)\n   Va a la farmacia. (She goes to the pharmacy.)\n\n2. Going to DO something (near future):\n   Voy a comer. (I am going to eat.)\n   Vamos a estudiar. (We are going to study.)\n\nRemember: a + el = al."},
        {type:"mc",q:"How do you say 'I am going to the museum'?",opts:["Voy al museo","Vas al museo","Va al museo","Vamos al museo"],ans:"Voy al museo",hint:"You need the yo form of ir, which is very irregular."},
        {type:"mc",q:"Vamos a estudiar español. What does this mean?",opts:["We study Spanish","We are going to study Spanish","We studied Spanish","We want to study Spanish"],ans:"We are going to study Spanish",hint:"Ir + a + infinitive expresses a near future action."},
        {type:"fb",opts:["va","voy","vas","vamos"],hint:"María is third person singular. Which form of ir matches?",s:"María {1} a la farmacia.",a:"va"},
        {type:"fb",opts:["van","va","vamos","vas"],hint:"Tus hermanos is third person plural. Which form fits?",s:"¿Adónde {1} tus hermanos?",a:"van"},
        {type:"mc",q:"¿Vas a comprar pan? What is being asked?",opts:["Do you like bread?","Did you buy bread?","Are you going to buy bread?","Where is the bread?"],ans:"Are you going to buy bread?",hint:"Ir + a + infinitive talks about something that will happen soon."},
        {type:"match",pairs:[{trg:"voy",src:"I go"},{trg:"vas",src:"you go"},{trg:"va",src:"he/she goes"},{trg:"vamos",src:"we go"},{trg:"van",src:"they go"}]},
        {type:"fb",opts:["vamos","van","voy","vas"],hint:"Nosotros needs the we form of this irregular verb.",s:"Nosotros {1} al parque en bicicleta.",a:"vamos"},
        {type:"mc",q:"Voy al banco. What does 'al' replace?",opts:["a + un","a + la","a + los","a + el"],ans:"a + el",hint:"This contraction only happens with the masculine singular article."},
        {type:"fb",opts:["Vas","Voy","Va","Van"],hint:"The question is directed at you (tú). Which form of ir fits?",s:"¿{1} a la estación en metro?",a:"Vas"},
        {type:"mc",q:"Mis padres van a viajar en avión. What are the parents going to do?",opts:["Travel by plane","Buy a plane","Go to the airport","Work at the airport"],ans:"Travel by plane",hint:"Van a + infinitive describes what they will do soon."},
        {type:"drag_fill",hint:"Match each subject to the correct form of ir.",s:"Yo {1} al supermercado y María {2} a la farmacia.",blanks:{"1":"voy","2":"va"},pool:["voy","va","vas","vamos"]}
  ]},
  {id:"esp7l6",title:"Venir de",icon:"🔙",xp:15,board:true,steps:[
        {type:"intro",title:"Venir de",desc:"Learn to say where you are coming from and contrast ir (to go) with venir (to come).",goals:["Conjugate venir in the present","Use venir de + place","Contrast ir and venir"]},
        {type:"teach",trg:"venir",src:"to come",pos:"verb",gender:null,phonetic:"beh-NEER",note:"Venir is irregular. The stem changes from e to ie in most forms.",example:"A: ¿De dónde vienes?\nB: Vengo de la estación.\nA: ¿Vienes en metro?",exampleSrc:"A: Where are you coming from?\nB: I come from the station.\nA: Are you coming by metro?",funFact:"The 'yo' form 'vengo' inserts a g that isn't in the infinitive. This -go pattern joins a small family: tengo (tener), pongo (poner), salgo (salir), hago (hacer). All high-frequency irregulars."},
        {type:"teach",trg:"vengo de",src:"I come from",pos:"intj",gender:null,phonetic:"BEN-goh deh",note:"Yo vengo. Note the g in the yo form, like tengo.",example:"A: ¿De dónde vienes?\nB: Vengo del supermercado.\nA: ¿Compraste fruta?",exampleSrc:"A: Where are you coming from?\nB: I come from the supermarket.\nA: Did you buy fruit?",funFact:"'Venir' + de signals origin. 'Vengo de Londres' = I come from London (origin now) OR I just came from London (recent motion). Tense-ambiguous by design."},
        {type:"teach",trg:"vienes de",src:"you come from (informal)",pos:"intj",gender:null,phonetic:"bee-EH-nehs deh",note:"Tú vienes. The stem changes: ven- becomes vien-.",example:"A: ¿Vienes del parque?\nB: Sí, vengo del parque.\nA: ¿Está bonito hoy?",exampleSrc:"A: Are you coming from the park?\nB: Yes, I come from the park.\nA: Is it nice today?",funFact:"Note the stem change: ven + go becomes viene for tú. All 'venir' conjugations show this e→ie pattern except nosotros (venimos) and vosotros (venís)."},
        {type:"teach",trg:"viene de",src:"he/she comes from",pos:"intj",gender:null,phonetic:"bee-EH-neh deh",note:"3rd person singular of venir (to come). 'Viene de + place' = he/she/you come from. Irregular stem: vien-.",example:"A: ¿De dónde viene Pedro?\nB: Viene del hospital.\nA: ¿Está bien?",exampleSrc:"A: Where is Pedro coming from?\nB: He comes from the hospital.\nA: Is he okay?",funFact:"Third-person singular. Frequently used for etymology: 'Viene del latín' = it comes from Latin. Standard academic Spanish opener."},
        {type:"teach",trg:"venimos de",src:"we come from",pos:"intj",gender:null,phonetic:"beh-NEE-mohs deh",note:"Nosotros venimos. No stem change in this form.",example:"A: ¿De dónde venís?\nB: Venimos del museo.\nA: ¿Os gustó?",exampleSrc:"A: Where are you coming from?\nB: We come from the museum.\nA: Did you like it?",funFact:"Nosotros form keeps the e (no diphthong): venimos, venís. The 'ie' only appears in stressed positions. Predictable for all e→ie stem-changing verbs."},
        {type:"tip",title:"Ir vs Venir",text:"Ir = movement AWAY from the speaker.\n  Voy al banco. (I am going to the bank.)\n\nVenir = movement TOWARD the speaker.\n  Vengo del banco. (I am coming from the bank.)\n\nKey difference:\n  ir + a (going TO a place)\n  venir + de (coming FROM a place)\n\nNote: de + el = del."},
        {type:"mc",q:"How do you say 'I come from the park'?",opts:["Vengo del parque","Voy al parque","Viene del parque","Vamos al parque"],ans:"Vengo del parque",hint:"You need the yo form of venir, plus from."},
        {type:"mc",q:"What does 'del' replace?",opts:["de + la","de + el","de + los","de + un"],ans:"de + el",hint:"This contraction works like al (a + el), but with a different preposition."},
        {type:"fb",opts:["viene","vengo","vienes","vienen"],hint:"María is third person singular. Which form of venir fits?",s:"¿De dónde {1} María?",a:"viene"},
        {type:"fb",opts:["venimos","vienen","vengo","viene"],hint:"Nosotros needs the we form of venir.",s:"Nosotros {1} de la estación.",a:"venimos"},
        {type:"mc",q:"Ir is to go TO a place. Venir is to come FROM a place. Which sentence uses venir correctly?",opts:["Voy de la farmacia","Vengo a la farmacia","Vengo de la farmacia","Vengo la farmacia"],ans:"Vengo de la farmacia",hint:"Venir always pairs with de, meaning from."},
        {type:"match",pairs:[{trg:"vengo",src:"I come"},{trg:"vienes",src:"you come"},{trg:"viene",src:"he/she comes"},{trg:"venimos",src:"we come"},{trg:"vienen",src:"they come"}]},
        {type:"mc",q:"Pedro viene del hospital. Where was Pedro?",opts:["Looking for the hospital","Going to the hospital","Near the hospital","At the hospital"],ans:"At the hospital",hint:"Venir de means coming FROM. He was there before."},
        {type:"fb",opts:["del","al","de la","a la"],hint:"Supermercado is masculine. De + el contracts to one word.",s:"Vengo {1} supermercado.",a:"del"},
        {type:"drag_fill",hint:"First you go there, then you come back from there.",s:"Yo {1} al banco y luego {2} del banco.",blanks:{"1":"voy","2":"vengo"},pool:["voy","vengo","va","viene"]},
        {type:"mc",q:"¿Vienes de la iglesia? What is being asked?",opts:["Are you coming from the church?","Are you going to the church?","Do you like the church?","Where is the church?"],ans:"Are you coming from the church?",hint:"Vienes de asks about your origin, not your destination."},
        {type:"fb",opts:["vienen","viene","venimos","vengo"],hint:"Mis padres is third person plural. Which form matches?",s:"Mis padres {1} del museo.",a:"vienen"},
        {type:"mc",q:"Which pair shows the correct contrast?",opts:["Voy de / vengo a","Voy a / vengo de","Voy al / vengo al","Voy del / vengo del"],ans:"Voy a / vengo de",hint:"Going pairs with to, and coming pairs with from."}
  ]},
  {id:"esp7l7",title:"¡Gira! ¡Sigue!",icon:"🔄",xp:15,board:true,steps:[
        {type:"intro",title:"¡Gira! ¡Sigue!",desc:"Learn to give commands using the tú imperative, the form used with friends and people you know.",goals:["Form tú imperatives for regular verbs","Learn key irregular tú imperatives","Give clear directions using commands"]},
        {type:"teach",trg:"gira",src:"turn (command)",pos:"verb",gender:null,phonetic:"HEE-rah",note:"From girar. Tú imperative of -ar verbs: drop -ar, add -a.",example:"A: ¿Cómo llego a la farmacia?\nB: Gira a la derecha en la esquina.\nA: ¿En la primera esquina?",exampleSrc:"A: How do I get to the pharmacy?\nB: Turn right at the corner.\nA: At the first corner?",funFact:"Imperative of 'girar' (to turn). Informal tú command. 'Gira a la derecha'; turn right. Driving instructions use these commands heavily."},
        {type:"teach",trg:"sigue",src:"continue, keep going (command)",pos:"verb",gender:null,phonetic:"SEE-geh",note:"From seguir (e to i stem change). Sigue todo recto = keep going straight.",example:"A: ¿Sigo todo recto?\nB: Sí, sigue todo recto dos calles.\nA: ¿Y luego?",exampleSrc:"A: Do I go straight?\nB: Yes, keep going straight two blocks.\nA: And then?",funFact:"Imperative of 'seguir' (to follow). Informal tu command. 'Sigue recto'; go straight. Stem change: e→i in all forms except nosotros/vosotros. Common street-direction verb."},
        {type:"teach",trg:"cruza",src:"cross (command)",pos:"verb",gender:null,phonetic:"KROO-sah",note:"From cruzar. Cruza la calle = cross the street.",example:"A: ¿Cruzo la calle?\nB: Sí, cruza la calle y gira a la izquierda.\nA: Entendido.",exampleSrc:"A: Do I cross the street?\nB: Yes, cross the street and turn left.\nA: Understood.",funFact:"Imperative of 'cruzar' (to cross). 'Cruza la calle'; cross the street. Regular -ar. Note spelling change: cruza → cruce in formal usted command (preserving the c-sound)."},
        {type:"teach",trg:"toma",src:"take (command)",pos:"verb",gender:null,phonetic:"TOH-mah",note:"From tomar. Toma la primera calle = take the first street.",example:"A: ¿Qué autobús tomo?\nB: Toma el autobús número 5.\nA: Gracias.",exampleSrc:"A: Which bus do I take?\nB: Take bus number 5.\nA: Thank you.",funFact:"Imperative of 'tomar' (to take). Tomar covers many senses: take, drink, get. 'Toma el autobus'; take the bus. Latin 'tomar' from 'autumare' (to claim)."},
        {type:"teach",trg:"para",src:"stop (command)",pos:"prep",gender:null,phonetic:"PA-rah",note:"From parar. Para aquí = stop here.",example:"A: ¿Paro aquí?\nB: Sí, para aquí. El banco está enfrente.\nA: Ah, ya lo veo.",exampleSrc:"A: Do I stop here?\nB: Yes, stop here. The bank is in front.\nA: Ah, I see it now.",funFact:"'Para' is identical in spelling to the common preposition 'para' (for/toward), so native speakers rely on intonation and context. The verb form drops the -r from the infinitive 'parar' (to stop)."},
        {type:"teach",trg:"ven",src:"come (command, irregular)",pos:"verb",gender:null,phonetic:"ben",note:"Irregular. The tú imperative of venir is just ven, not viene.",example:"A: ¡Ven aquí!\nB: ¿Qué pasa?\nA: Ven, te enseño algo.",exampleSrc:"A: Come here!\nB: What is it?\nA: Come, I will show you something.",funFact:"Imperative of 'venir' (to come). One of nine irregular tu commands (along with di, haz, pon, sal, se, ten, ve, ven). Latin 'venire'; same root as English 'venue,' 'advent,' 'convene.'"},
        {type:"tip",title:"Tú Imperative: Regular Verbs",text:"To form the tú command for regular verbs:\n\n-ar verbs: drop -ar, add -a\n  girar: gira (turn)\n  cruzar: cruza (cross)\n  tomar: toma (take)\n  parar: para (stop)\n\n-er/-ir verbs: drop -er/-ir, add -e\n  comer: come (eat)\n  seguir: sigue (continue)\n\nIrregulars to memorize:\n  venir: ven (come)\n  ir: ve (go)\n  salir: sal (leave/go out)"},
        {type:"mc",q:"How do you tell a friend to turn left?",opts:["Gira a la izquierda","Giras a la izquierda","Girar a la izquierda","Giramos a la izquierda"],ans:"Gira a la izquierda",hint:"The tú imperative of -ar verbs ends in -a, without the -s."},
        {type:"mc",q:"What does 'Cruza la calle' mean?",opts:["The street crosses","Cross the street","I cross the street","Crossing the street"],ans:"Cross the street",hint:"This is a command form, telling someone to do something."},
        {type:"fb",opts:["Sigue","Sigues","Seguir","Sigo"],hint:"You need the tú command form, telling someone to continue.",s:"{1} todo recto y luego gira a la derecha.",a:"Sigue"},
        {type:"fb",opts:["Toma","Tomas","Tomar","Tomo"],hint:"You are telling a friend which bus to catch. Use the command form.",s:"{1} el autobús número 3.",a:"Toma"},
        {type:"match",pairs:[{trg:"gira",src:"turn"},{trg:"sigue",src:"continue"},{trg:"cruza",src:"cross"},{trg:"toma",src:"take"},{trg:"para",src:"stop"},{trg:"ven",src:"come"}]},
        {type:"mc",q:"Which option is the correct informal command for the movement verb meaning 'to come'?",opts:["vienes","viene","ven","vengo"],ans:"ven",hint:"This verb has an irregular command form that is very short."},
        {type:"drag_fill",hint:"First you go across the road, then you change direction.",s:"{1} la calle y {2} a la derecha.",blanks:{"1":"Cruza","2":"gira"},pool:["Cruza","gira","sigue","para"]},
        {type:"fb",opts:["Ven","Viene","Vienes","Vengo"],hint:"You are calling someone to come to where you are. Irregular command.",s:"¡{1} aquí! Quiero enseñarte algo.",a:"Ven"},
        {type:"mc",q:"Which is the correct set of directions? 'Sigue todo recto, gira a la izquierda, y el banco está en la esquina.'",opts:["Take the first street, turn right, the bank is on the left","Turn right, go straight, the bank is far","Cross the street, stop, the bank is behind you","Go straight, turn left, the bank is on the corner"],ans:"Go straight, turn left, the bank is on the corner",hint:"Translate each command in order: sigue, gira, esquina."},
        {type:"mc",q:"Which option is the correct informal command for the verb meaning 'to go out or leave'?",opts:["sal","sale","sales","salir"],ans:"sal",hint:"Like the command for 'come', this is an irregular short form."}
  ]},
  {id:"esp7l8b",title:"Las Direcciones Cardinales",icon:"🧭",xp:20,board:true,steps:[
        {type:"intro",title:"Las Direcciones Cardinales",desc:"Learn north, south, east, and west in Spanish. Use directions to talk about geography and location.",goals:["Learn the four cardinal directions","Use 'al norte de' pattern for relative location","Talk about Spanish-speaking countries and geography"]},
        {type:"teach",trg:"el norte",src:"the north",pos:"noun",gender:"m",note:"El norte = the north. Masculine noun.\nUsed with en el norte (in the north).",example:"A: ¿Dónde está Canadá?\nB: Canadá está en el norte de América.\nA: ¿Hace frío allí?",exampleSrc:"A: Where is Canada?\nB: Canada is in the north of America.\nA: Is it cold there?",funFact:"Cognate with English 'north'. Spanish and English share many Latin-derived words."},
        {type:"teach",trg:"el sur",src:"the south",pos:"noun",gender:"m",note:"El sur = the south. Masculine noun.\nAmérica del Sur = South America.",example:"A: ¿De dónde es el tango?\nB: El tango es de Argentina, en el sur.\nA: ¡Qué bonito baile!",exampleSrc:"A: Where is tango from?\nB: Tango is from Argentina, in the south.\nA: What a beautiful dance!",funFact:"South. From Germanic 'sunthra-' via Old French. Same root as English 'south.' Spanish cardinal directions (norte, sur, este, oeste) are all loanwords."},
        {type:"teach",trg:"el este",src:"the east",pos:"noun",gender:"m",note:"El este = the east. Masculine noun.\nSalir = to rise (for the sun). Ponerse = to set.",example:"A: ¿Dónde sale el sol?\nB: El sol sale por el este.\nA: ¿Y se pone por el oeste?",exampleSrc:"A: Where does the sun rise?\nB: The sun rises in the east.\nA: And it sets in the west?",funFact:"East. From Germanic 'austra-' (dawn) via Old French. Same root as English 'east.' Across Romance languages these cardinal direction words are remarkably consistent."},
        {type:"teach",trg:"el oeste",src:"the west",pos:"noun",gender:"m",note:"El oeste = the west. Masculine noun.\nPuesta de sol = sunset.",example:"A: ¿Dónde se pone el sol?\nB: El sol se pone por el oeste.\nA: Me gusta ver la puesta de sol.",exampleSrc:"A: Where does the sun set?\nB: The sun sets in the west.\nA: I like to watch the sunset.",funFact:"West. From Germanic 'west-' via Old French. English 'west' is the same word. Medieval Spanish still used 'poniente' (setting sun) for west."},
        {type:"tip",title:"Al norte de: Relative Position",deepDive:{
          title:"Why 'al' and not 'en el'?",
          text:"Al norte de describes RELATIVE position. One place is north of another.\n\nEn el norte de describes ABSOLUTE position within a region.\n\nBarcelona está al este de Madrid. (relative)\nBarcelona está en el este de España. (within Spain)"
        },text:"To say something is north/south/east/west OF a place:\n\nal norte de = to the north of\nal sur de = to the south of\nal este de = to the east of\nal oeste de = to the west of\n\nBarcelona está al este de Madrid.\nMéxico está al sur de Estados Unidos."},
        {type:"teach",trg:"al norte de",src:"to the north of",pos:"verb",gender:null,note:"Al norte de = to the north of.\nUsed to describe relative position between places.",example:"A: ¿Dónde está Francia?\nB: Francia está al norte de España.\nA: ¿Y Portugal?\nB: Portugal está al oeste de España.",exampleSrc:"A: Where is France?\nB: France is to the north of Spain.\nA: And Portugal?\nB: Portugal is to the west of Spain.",funFact:"Compound preposition. 'Al norte de Madrid'; to the north of Madrid. Cardinal directions all take 'al + direction + de + place.'"},
        {type:"teach",trg:"al sur de",src:"to the south of",pos:"verb",gender:null,note:"Al sur de = to the south of.\nMarruecos = Morocco.",example:"A: ¿Dónde está Marruecos?\nB: Marruecos está al sur de España.\nA: ¿Está muy lejos?",exampleSrc:"A: Where is Morocco?\nB: Morocco is to the south of Spain.\nA: Is it very far?",funFact:"Same pattern. 'Al sur de España'; to the south of Spain. Often used for regions: al sur de Andalucía (southern Andalusia)."},
        {type:"teach",trg:"América del Norte",src:"North America",pos:"intj",gender:null,note:"América del Norte = North America.\nAmérica del Sur = South America.\nDel = de + el.",example:"A: ¿Cuántos países hay en América del Norte?\nB: Hay tres: Canadá, Estados Unidos y México.\nA: ¿México es parte de América del Norte?",exampleSrc:"A: How many countries are in North America?\nB: There are three: Canada, the United States, and Mexico.\nA: Is Mexico part of North America?",funFact:"Preferred over 'Norteamérica' in formal Spanish writing. The 'de + cardinal direction' pattern is universal: América del Sur, Europa del Este, Asia del Sureste."},
        {type:"teach",trg:"Europa del Este",src:"Eastern Europe",pos:"intj",gender:null,note:"Europa del Este = Eastern Europe.\nEuropa del Oeste = Western Europe.",example:"A: ¿Eres de Europa del Este?\nB: Sí, soy de Polonia.\nA: ¡Qué bien!",exampleSrc:"A: Are you from Eastern Europe?\nB: Yes, I am from Poland.\nA: How nice!",funFact:"Cold War era framing. Since 1991, younger speakers sometimes prefer 'Europa Central y Oriental' for accuracy. The old term persists in news."},
        {type:"mc",q:"Where does the sun rise?",opts:["Por el este","Por el norte","Por el oeste","Por el sur"],ans:"Por el este",hint:"The direction associated with sunrise, where morning begins."},
        {type:"mc",q:"Francia está ___ de España.",opts:["al sur","al norte","al este","al oeste"],ans:"al norte",hint:"France is above Spain on the map."},
        {type:"fb",opts:["al","el","en","del"],hint:"The pattern for relative location uses this contraction of a + el.",s:"México está {1} sur de Estados Unidos.",a:"al"},
        {type:"match",pairs:[{trg:"el norte",src:"north"},{trg:"el sur",src:"south"},{trg:"el este",src:"east"},{trg:"el oeste",src:"west"},{trg:"al norte de",src:"to the north of"}]},
        {type:"mc",q:"'América del Sur' uses 'del' because:",opts:["It is a special phrase","del means 'the' here","del = de + el (Sur is masculine)","América is feminine"],ans:"del = de + el (Sur is masculine)",hint:"The contraction de + el forms this single word."},
        {type:"fb",opts:["oeste","este","norte","sur"],hint:"Portugal is on the left side of Spain on the map.",s:"Portugal está al {1} de España.",a:"oeste"},
        {type:"mc",q:"How do you say 'Morocco is to the south of Spain'?",opts:["Marruecos está en sur de España","Marruecos está el sur de España","Marruecos está del sur de España","Marruecos está al sur de España"],ans:"Marruecos está al sur de España",hint:"The pattern is: al + direction + de + place name."},
        {type:"drag_fill",hint:"Both positions use the same pattern for relative location.",s:"Canadá está {1} norte de Estados Unidos y México está {2} sur.",blanks:{"1":"al","2":"al"},pool:["al","al","el","del"]},
        {type:"tip",title:"The Spanish-Speaking World",text:"Spanish is spoken across many regions:\n\nAmérica del Norte: México\nAmérica Central: Guatemala, Honduras, El Salvador, Nicaragua, Costa Rica, Panamá\nAmérica del Sur: Colombia, Venezuela, Ecuador, Perú, Bolivia, Chile, Argentina, Uruguay, Paraguay\nEuropa: España\nÁfrica: Guinea Ecuatorial",icon:"🌍"},
        {type:"fb",opts:["sur","norte","este","oeste"],hint:"Argentina is the southernmost major country of the continent.",s:"El Polo {1} se encuentra en el extremo del planeta.",a:"sur"},
        {type:"mc",q:"Which is correct? 'Barcelona está ___ de Madrid.'",opts:["al este","al norte","al sur","al oeste"],ans:"al este",hint:"Barcelona is on the Mediterranean coast, toward where the sun rises."},
        {type:"match",pairs:[
          {trg:"América del Norte",src:"North America"},
          {trg:"América del Sur",src:"South America"},
          {trg:"Europa del Este",src:"Eastern Europe"},
          {trg:"al norte de",src:"to the north of"},
          {trg:"al sur de",src:"to the south of"}
        ]}
  ]},
  {id:"esp7l8",title:"¿Cómo Llego?",icon:"🧭",xp:15,board:true,steps:[
        {type:"intro",title:"¿Cómo Llego?",desc:"Combine everything from this unit: places, directions, transport, ir, venir, and commands in real-world scenarios.",goals:["Navigate a city using Spanish","Combine directions with transport","Handle real direction conversations"]},
        {type:"teach",trg:"¿Está lejos?",src:"Is it far?",pos:"intj",gender:null,phonetic:"es-TA LEH-hos",note:"A useful follow-up when someone gives you directions.",example:"A: ¿Cómo llego al museo?\nB: Sigue todo recto cinco minutos.\nA: ¿Está lejos?",exampleSrc:"A: How do I get to the museum?\nB: Go straight for five minutes.\nA: Is it far?",funFact:"'Lejos' is an adverb meaning 'far'; distance from a reference point. Pairs with 'cerca' (near). Both are invariable: no gender agreement."},
        {type:"teach",trg:"a pie",src:"on foot, walking",pos:"intj",gender:null,phonetic:"ah pee-EH",note:"The only transport that does not use en. A pie = on foot.",example:"A: ¿Vamos a pie o en autobús?\nB: Vamos a pie. No está lejos.\nA: ¡Vale, vamos!",exampleSrc:"A: Shall we walk or take the bus?\nB: Let's walk. It is not far.\nA: Okay, let's go!",funFact:"Literally 'on foot.' The 'a' preposition covers manner of transport: a pie (walking), a caballo (on horseback), a mano (by hand). 'En' is for vehicles: en coche, en tren."},
        {type:"teach",trg:"la parada",src:"the stop (bus/metro)",pos:"noun",gender:"f",phonetic:"la pa-RA-dah",note:"La parada de autobús = bus stop. La parada de metro = metro stop.",example:"A: ¿Dónde está la parada de autobús?\nB: Está en la esquina de la calle.\nA: Gracias, voy para allá.",exampleSrc:"A: Where is the bus stop?\nB: It is on the corner of the street.\nA: Thank you, I will head there.",funFact:"Stop (transport). From 'parar' (to stop). Literally 'the stopping.' Spanish -ada endings often form nouns from verbs: jugar → jugada, llamar → llamada."},
        {type:"teach",trg:"el semáforo",src:"the traffic light",pos:"noun",gender:"m",phonetic:"el seh-MA-foh-roh",note:"A useful landmark when giving directions.",example:"A: ¿Dónde giro?\nB: Gira a la derecha en el semáforo.\nA: ¿En el primer semáforo?",exampleSrc:"A: Where do I turn?\nB: Turn right at the traffic light.\nA: At the first traffic light?",funFact:"Traffic light. From Greek 'sema' (sign) + 'phoros' (bearer). Coined in the 19th century for modern traffic control. Spanish borrowed the neologism intact."},
        {type:"teach",trg:"está muy cerca",src:"it is very close",pos:"intj",gender:null,phonetic:"es-TA mooy SEHR-kah",note:"Cerca = close, lejos = far. You already know these.",example:"A: ¿Está lejos la farmacia?\nB: No, está muy cerca. A cinco minutos a pie.\nA: Perfecto.",exampleSrc:"A: Is the pharmacy far?\nB: No, it is very close. Five minutes on foot.\nA: Perfect.",funFact:"'Cerca' without 'de' is adverbial ('close by'). 'Cerca de' is prepositional ('close to something'). A tiny but crucial distinction that English collapses."},
        {type:"tip",title:"Complete Direction Dialogue",text:"A typical direction exchange:\n\n1. Get attention: Perdone / Disculpe\n2. Ask: ¿Dónde está...? / ¿Cómo llego a...?\n3. Receive directions: Sigue, gira, cruza, toma...\n4. Clarify: ¿Está lejos? / ¿Puedo ir a pie?\n5. Thank: Muchas gracias."},
        {type:"mc",q:"How do you say 'on foot' in Spanish?",opts:["A pie","En pie","Con pie","De pie"],ans:"A pie",hint:"This is the exception to the en + transport pattern."},
        {type:"mc",q:"¿Dónde está la parada de autobús? What is a 'parada'?",opts:["A street","A stop","A corner","A bridge"],ans:"A stop",hint:"This is the place where the bus picks up passengers."},
        {type:"fb",opts:["semáforo","esquina","calle","parque"],hint:"You turn at the object with red, yellow, and green lights.",s:"Gira a la izquierda en el {1}.",a:"semáforo"},
        {type:"fb",opts:["cerca","lejos","grande","recto"],hint:"The opposite of lejos, meaning the place is nearby.",s:"No, no está lejos. Está muy {1}.",a:"cerca"},
        {type:"mc",q:"Perdone, ¿cómo llego a la estación? 'Sigue todo recto, cruza la calle en el semáforo, y la estación está a la izquierda.' Which direction is NOT mentioned?",opts:["Cross the street","Go straight","Turn right","It is on the left"],ans:"Turn right",hint:"Read each instruction: recto, cruza, izquierda. What is missing?"},
        {type:"drag_fill",hint:"First ask for location, then give the turning command.",s:"Perdone, ¿{1} está el banco? Sigue todo recto y {2} a la derecha.",blanks:{"1":"dónde","2":"gira"},pool:["dónde","gira","viene","del"]},
        {type:"match",pairs:[{trg:"a pie",src:"on foot"},{trg:"la parada",src:"the stop"},{trg:"el semáforo",src:"the traffic light"},{trg:"está lejos",src:"it is far"},{trg:"está cerca",src:"it is close"}]},
        {type:"mc",q:"Vengo de la estación y voy al museo. Which verbs describe the speaker's journey?",opts:["Coming to + going from","Going from + coming to","Staying at + going to","Coming from + going to"],ans:"Coming from + going to",hint:"Venir de means ___ from, and ir a means ___ to."},
        {type:"fb",opts:["a","en","de","por"],hint:"Walking uses a special preposition, not the usual en.",s:"¿Puedo ir {1} pie? No está lejos.",a:"a"},
        {type:"drag_fill",hint:"Banco is masculine. Going TO uses a+el, coming FROM uses de+el.",s:"Voy {1} banco en metro y vengo {2} banco en taxi.",blanks:{"1":"al","2":"del"},pool:["al","del","a la","de la"]},
        {type:"mc",q:"A tourist asks you: '¿Dónde está el hospital?' You reply: 'Sigue todo recto, toma la segunda calle a la izquierda, y el hospital está al final de la calle.' How many direction steps did you give?",opts:["Three","Two","Four","One"],ans:"Three",hint:"Count each separate instruction: sigue, toma, está al final."}
  ]}
]};
